SELECT PRICES.SPHKEY1, PRICDETL.SpdDateEff, PRICDETL.SpdValue1 FROM NISAINT_CS\PRICDETL PRICDETL, NISAINT_CS\PRICES PRICES WHERE PRICES.SPHLINK = PRICDETL.SpdLink AND (PRICES.SPHTYPE=0) AND (PRICES.SPHBASIS=0) AND (PRICES.SPHPERIOD=1) AND (PRICES.SPHRT=15) AND (PRICES.SPHKEY2='REBVSELL') AND PRICDETL.SpdDateEff>current_date()-365 order by sphkey1, spddateeff
